172	  async getMany(listQuery: ListQuery, filters?: BuybackSearchFilters) {
173	    const userId = this.contextService.context.user.id;
174	
175	    const repository = this.txHost.tx.getRepository(BuybackRequestEntity);
176	
177	    const query = repository
178	      .createQueryBuilder('buyback_request')
179	      .select([
180	        'buyback_request.id',
181	        'buyback_request.status',
182	        'buyback_request.stage',
183	        'buyback_request.createdAt',
184	      ])
185	      .leftJoin('buyback_request.buyback', 'buyback')
186	      .addSelect(['buyback.id', 'buyback.type', 'buyback.status'])
187	      .where('buyback.sellerId = :userId', { userId })
188	      .andWhere('buyback.status = :status', { status: BuybackStatus.Quote })
189	      .leftJoin('buyback.asset', 'asset')
190	      .addSelect(['asset.id', 'asset.meta', 'asset.categoryFields'])
191	      .leftJoin('asset.category', 'category')
192	      .addSelect(['category.id', 'category.name'])
193	      .leftJoin('asset.photos', 'photos')
194	      .addSelect(['photos.id'])
195	      .skip(listQuery.skip)
196	      .take(listQuery.take)
197	      .orderBy('buyback_request.createdAt', listQuery?.order || 'DESC');
198	
199	    if (filters?.types) {
200	      query.andWhere('buyback.type IN (:...types)', { types: filters.types });
201	    }
202	
203	    if (filters?.categories) {
204	      query.andWhere('category.id IN (:...categories)', {
205	        categories: filters.categories,
206	      });
207	    }
208	
209	    if (filters?.search) {
210	      query.andWhere(
211	        new Brackets((qb) => {
212	          qb.where('category.name ILIKE :search')
213	            .orWhere("asset.categoryFields->>'brandName' ILIKE :search")
214	            .orWhere("asset.categoryFields->>'modelName' ILIKE :search");
215	        }),
216	        { search: `%${filters.search}%` },
217	      );
218	    }
219	
220	    const [results, total] = await query.getManyAndCount();
221	
222	    return {
223	      total,
224	      data: results,
225	      skip: listQuery.skip,
226	      take: listQuery.take,
227	    };
228	  }
